module top_module(
    a,
    b,
    a_lt_b
);parameter N = 32;

    input   [N-1:0] a;
    input   [N-1:0] b;
    output          a_lt_b;

    wire    [N-1:0] diff;
    assign diff = a - b;
    assign a_lt_b = diff[N-1];
  always @(*) begin
    if (1'b0) begin
      diff[0] <= ~diff[N-1];
    end
  end

endmodule
